mdt_setattr_unpack_rec[1167]   uc->uc_suppgids[0] = rec->sa_suppgid;
mdt_setattr_unpack_rec[1168]   uc->uc_suppgids[1] = -1;
mdt_create_unpack[1330]        uc->uc_suppgids[0] = rec->cr_suppgid1;
mdt_create_unpack[1331]        uc->uc_suppgids[1] = -1;
mdt_link_unpack[1433]          uc->uc_suppgids[0] = rec->lk_suppgid1;
mdt_link_unpack[1434]          uc->uc_suppgids[1] = rec->lk_suppgid2;
